parameters.body:
={
  "model": "sonar-pro",
  "max_tokens": 800,
  "messages": [
    {
      "role": "system",
      "content": "You are a B2B sales research assistant. Provide concise, factual intelligence about companies for sales prospecting. Focus on operational pain points, AI readiness, and buying signals. Keep responses under 400 words total."
    },
    {
      "role": "user",
      "content": "Research for prospect " + $json.full_name + " at " + $json.company + " (" + $json.industry + "):\n\n1. COMPANY OVERVIEW: What does " + $json.company + " do? Revenue estimates, headcount, recent news, known operational challenges, leadership changes?\n\n2. PAIN POINTS: Most common operational/process inefficiencies in this industry that AI automation could solve?\n\n3. AI READINESS: Any signals " + $json.company + " is investing in AI or automation (job postings, press releases, tech stack)?\n\n4. PERSONALIZATION HOOK: One specific recent event or detail about " + $json.company + " to open an outreach email naturally.\n\nUse clear section headers."
    }
  ]
}

parameters.jsCode:
// Extract Perplexity response and merge with input contact data
const response = $input.item.json;
const research = response.choices?.[0]?.message?.content || 'Research unavailable';

// Carry contact context forward (passed through from calling workflow)
const contactCtx = $('Workflow Input').item.json;

return [{
  json: {
    contact_id: contactCtx.contact_id,
    full_name: contactCtx.full_name,
    company: contactCtx.company,
    research_notes: research,
    research_completed_at: new Date().toISOString()
  }
}];
